    "cases": [
        {
            "input": {
                "op": "resources_by_version",
                "style": "core",
                "group_version": "v1",
                "kinds": ["Pod", "CronJob"],
                "queries": ["v1", "v2"]
            },
            "expected_output": "group=v1 kinds=CronJob,Pod\ngroup=v2 kinds=\n"
        }
    ]
}
```

